"use client";

import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
} from "recharts";

type TrendRow = {
  month: string;
  students: number;
  newStudents?: number;
};

export default function DashboardChart({
  data = [],
}: {
  data?: TrendRow[];
}) {
  const chartData =
    Array.isArray(data) && data.length
      ? data
      : [
          "Jan",
          "Feb",
          "Mar",
          "Apr",
          "May",
          "Jun",
        ].map((month) => ({
          month,
          students: 0,
          newStudents: 0,
        }));
  const hasStudentData =
    chartData.some(
      (row) =>
        Number(row.students || 0) > 0 ||
        Number(row.newStudents || 0) > 0
    );

  return (

    <div
      className="
        bg-white
        rounded-3xl
        p-6
        shadow
      "
    >

      <h2 className="text-2xl font-bold mb-5">
        Student Growth Trend
      </h2>

      <div className="h-[300px]">

        <ResponsiveContainer
          width="100%"
          height="100%"
        >

          <LineChart
            data={chartData}
            margin={{
              top: 8,
              right: 18,
              left: 0,
              bottom: 8,
            }}
          >

            <CartesianGrid
              stroke="#e5e7eb"
              strokeDasharray="4 4"
            />

            <XAxis
              dataKey="month"
              tick={{
                fill: "#334155",
                fontWeight: 700,
              }}
              axisLine={{
                stroke: "#cbd5e1",
              }}
              tickLine={false}
            />

            <YAxis
              allowDecimals={false}
              tick={{
                fill: "#334155",
                fontWeight: 700,
              }}
              axisLine={{
                stroke: "#cbd5e1",
              }}
              tickLine={false}
            />

            <Tooltip
              formatter={(value, name) => [
                value,
                name === "newStudents"
                  ? "New Students"
                  : "Total Students",
              ]}
              contentStyle={{
                borderRadius: 12,
                borderColor: "#fbbf24",
                boxShadow:
                  "0 18px 45px rgba(15, 23, 42, 0.15)",
              }}
            />

            <Line
              type="monotone"
              dataKey="students"
              name="Total Students"
              stroke="#0f172a"
              strokeWidth={3}
              dot={{
                r: 4,
                fill: "#d4af37",
                stroke: "#0f172a",
                strokeWidth: 2,
              }}
              activeDot={{
                r: 6,
                fill: "#d4af37",
                stroke: "#0f172a",
                strokeWidth: 2,
              }}
            />

            <Line
              type="monotone"
              dataKey="newStudents"
              name="New Students"
              stroke="#d4af37"
              strokeWidth={2}
              strokeDasharray="6 5"
              dot={false}
            />

          </LineChart>

        </ResponsiveContainer>

      </div>

      {!hasStudentData ? (
        <p className="mt-4 rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm font-semibold text-amber-900">
          No student admission records found for the selected school and academic year yet.
        </p>
      ) : null}

    </div>

  );

}
