"use client";

import {
  useEffect,
  useState,
  type ReactNode,
} from "react";

import TottechAIBadge from "@/components/ai/TottechAIBadge";

export default function QuickActions() {
  const [aiName, setAiName] =
    useState("School Assistant");

  useEffect(() => {
    let active = true;

    fetch("/api/my-school-branding")
      .then((response) =>
        response.json()
      )
      .then((data) => {
        if (active) {
          setAiName(
            data.aiDisplayName ||
              data.assistantName ||
              "School Assistant"
          );
        }
      })
      .catch(console.error);

    return () => {
      active = false;
    };
  }, []);

  const actions: {
    title: string;
    href: string;
    icon: ReactNode;
    featured?: boolean;
  }[] = [

    {
      title: "Add Student",
      href: "/students",
      icon: "🎓",
    },

    {
      title: "Add Teacher",
      href: "/teachers",
      icon: "👨‍🏫",
    },

    {
      title: "Create Exam",
      href: "/academics/exam-schedule",
      icon: "📝",
    },

    {
      title: "Collect Fee",
      href: "/finance/collection",
      icon: "💰",
    },

    {
      title: aiName,
      href: "/ai-school-copilot",
      icon: (
        <TottechAIBadge
          size="sm"
          label={aiName}
          tagline="School Copilot"
        />
      ),
      featured: true,
    },

  ];

  return (

    <div
      className="
        grid
        grid-cols-2
        md:grid-cols-5
        gap-4
      "
    >

      {actions.map((action) => (

        <a
          key={action.title}
          href={action.href}
          className={`
            tt-card
            p-4
            text-center
            transition-all
            hover:border-amber-300
            hover:shadow-xl
            ${
              action.featured
                ? "border-amber-300 bg-amber-50/60 shadow-[0_16px_44px_rgba(245,158,11,0.12)]"
                : ""
            }
          `}
        >

          <div className="mx-auto mb-2 flex h-10 w-10 items-center justify-center rounded-lg bg-amber-50 text-xl">
            {action.icon}
          </div>

          <div className="text-sm font-bold text-slate-950">
            {action.title}
          </div>

        </a>

      ))}

    </div>

  );

}
